**Nota:** Este es un ejemplo básico y no debe usarse en producción sin más pruebas y validaciones.

```python
import unittest
import hashlib
import getpass

class SistemaSeguridad:
    def __init__(self):
        self.usuarios = {}

    def registrar_usuario(self, nombre, contraseña):
        # Generar hash de la contraseña
        contraseña_hash = self._generar_hash_contraseña(contraseña)
        self.usuarios[nombre] = contraseña_hash

    def verificar_contraseña(self, nombre, contraseña):
        # Verificar si el usuario existe
        if nombre not in self.usuarios:
            return False

        # Generar hash de la contraseña ingresada
        contraseña_ingresada_hash = self._generar_hash_contraseña(contraseña)

        # Comparar el hash de la contraseña ingresada con el almacenado
        return self.usuarios[nombre] == contraseña_ingresada_hash

    @staticmethod
    def _generar_hash_contraseña(contraseña):
        # Utilizar el algoritmo SHA-256 para generar el hash
        return hashlib.sha256(contraseña.encode()).hexdigest()

class PruebaSeguridad(unittest.TestCase):
    def setUp(self):
        self.sistema = SistemaSeguridad()

    def test_registrar_usuario(self):
        self.sistema.registrar_usuario('juan', 'contraseña123')
        self.assertIn('juan', self.sistema.usuarios)

    def test_verificar_contraseña_correcta(self):
        self.sistema.registrar_usuario('juan', 'contraseña123')
        self.assertTrue(self.sistema.verificar_contraseña('juan', 'contraseña123'))

    def test_verificar_contraseña_incorrecta(self):
        self.sistema.registrar_usuario('juan', 'contraseña123')
        self.assertFalse(self.sistema.verificar_contraseña('juan', 'contraseña456'))

    def test_verificar_usuario_no_existe(self):
        self.assertFalse(self.sistema.verificar_contraseña('juan', 'contraseña123'))

if __name__ == '__main__':
    unittest.main()
